import React from 'react';
import NavBar from './components/NavBar';

function App() {
  return (
    <div>
      <NavBar />
      <div className="container mt-4">
        <h2>Bienvenido a la Tienda de Simuladores</h2>
        <p>Explora nuestras categorías y encuentra los mejores simuladores para ti.</p>
      </div>
    </div>
  );
}

export default App;
